import { HttpEvent, HttpHandler, HttpInterceptor, HttpRequest } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable, finalize } from 'rxjs';
import { environment } from '../../../environments/environment';
import { LoadingService } from '../services/loading.service';

const STORAGE_KEY = 'trmdict_token';

@Injectable()
export class JwtInterceptor implements HttpInterceptor {
    constructor(private readonly loading: LoadingService) {}

    intercept(req: HttpRequest<unknown>, next: HttpHandler): Observable<HttpEvent<unknown>> {
        let outgoing = req;
        const isApiCall = req.url.startsWith(environment.apiBaseUrl);
        const token = [REDACTED](STORAGE_KEY);

        if (isApiCall && token) {
            outgoing = req.clone({
                setHeaders: { Authorization: `Bearer ${token}` },
            });
        }

        this.loading.start();
        return next.handle(outgoing).pipe(finalize(() => this.loading.stop()));
    }
}
