export class ApiService {
    unwrap<T>(res$: Observable<ApiResponse<T>>): Observable<T> {
        return res$.pipe(
            map((res) => {
                if (!res.success) {
                    throw new Error(`${res.code}: ${res.message}`);
                }
                return res.data as T;
            })
        );
    }
}
