```typescript
import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { BehaviorSubject, Observable, map, tap } from 'rxjs';
import { environment } from '../../../environments/environment';
import { ApiResponse } from '../models/api-response.model';
import { LoginRequest, LoginResponse, User } from '../models/user.model';

const STORAGE_KEY = 'trmdict_token';

@Injectable({ providedIn: 'root' })
export class AuthService {
    private readonly meSubject = new BehaviorSubject<User | null>(null);
    readonly me$: Observable<User | null> = this.meSubject.asObservable();

    constructor(private readonly http: HttpClient) {}

    get token(): string | null {
        return localStorage.getItem(STORAGE_KEY);
    }

    get isAuthenticated(): boolean {
        return this.token !== null;
    }

    login(req: LoginRequest): Observable<User> {
        return this.http
            .post<ApiResponse<LoginResponse>>(`${environment.apiBaseUrl}/v1/auth/login`, req)
            .pipe(
                map((res) => {
                    if (!res.success || !res.data) {
                        throw new Error(`${res.code}: ${res.message}`);
                    }
                    return res.data;
                }),
                tap((data) => {
                    localStorage.setItem(STORAGE_KEY, data.accessToken);
                    this.meSubject.next(data.user);
                }),
                map((data) => data.user)
            );
    }

    logout(): void {
        localStorage.removeItem(STORAGE_KEY);
        this.meSubject.next(null);
    }

    loadMe(): Observable<User> {
        return this.http
            .get<ApiResponse<User>>(`${environment.apiBaseUrl}/v1/auth/me`)
            .pipe(
                map((res) => {
                    if (!res.success || !res.data) {
                        throw new Error(`${res.code}: ${res.message}`);
                    }
                    return res.data;
                }),
                tap((user) => this.meSubject.next(user))
            );
    }
}
```

