{"type": "text", "file": {"filePath": "D:\20. POC\TrmWordDict\backend\src\main\java\com\devwogns\trmdict\common\paging\PageRequest.java", "content": "package com.devwogns.trmdict.common.paging;

import lombok.AccessLevel;
import lombok.AllArgsConstructor;
import lombok.Getter;

import java.util.Set;

@Getter
@AllArgsConstructor(access = AccessLevel.PRIVATE)
public class PageRequest {

    private final int page;          // 1-based
    private final int size;
    private final String sortColumn; // �겢�씪�씠�뼵�듃 �엯�젰 (�젙洹쒗솕 �븞 �맖)
    private final String sortDirection;

    public static PageRequest of(int page, int size, String sortColumn, String sortDirection) {
        int safePage = Math.max(1, page);
        int safeSize = Math.max(1, size);
        String safeColumn = sortColumn == null ? "" : sortColumn.trim();
        String safeDirection = normalizeDirection(sortDirection);
        return new PageRequest(safePage, safeSize, safeColumn, safeDirection);
    }

    public int getOffset() {
        return (page - 1) * size;
    }

    public int getLimit() {
        return size;
    }

    /**
     * sortColumn�씠 �솕�씠�듃由ъ뒪�듃�뿉 �룷�븿�릺硫� 洹몃��濡�, �븘�땲硫� defaultColumn 諛섑솚.
     * defaultColumn�씠 �솕�씠�듃由ъ뒪�듃�뿉 �뾾�쑝硫� IllegalArgumentException.
     */
    public String resolveSortColumn(Set<String> whitelist, String defaultColumn) {
        if (!whitelist.contains(defaultColumn)) {
            throw new IllegalArgumentException(
                    "default sort column '" + defaultColumn + "' must be in whitelist " + whitelist);
        }
        return whitelist.contains(sortColumn) ? sortColumn : defaultColumn;
    }

    private static String normalizeDirection(String input) {
        if (input == null) return "DESC";
        String upper = input.trim().toUpperCase();
        return ("ASC".equals(upper) || "DESC".equals(upper)) ? upper : "DESC";
    }
}
