{"type": "text", "file": {"filePath": "D:\20. POC\TrmWordDict\backend\src\main\java\com\devwogns\trmdict\common\exception\GlobalExceptionHandler.java", "content": "package com.devwogns.trmdict.common.exception;

import com.devwogns.trmdict.common.response.ApiResponse;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.ResponseEntity;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

@Slf4j
@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(BusinessException.class)
    public ResponseEntity<ApiResponse<Void>> handleBusiness(BusinessException ex) {
        ErrorCode code = ex.getErrorCode();
        log.info("[BusinessException] {} - {}", code.getCode(), ex.getMessage());
        return ResponseEntity.status(code.getHttpStatus())
                .body(ApiResponse.error(code.getCode(), ex.getMessage()));
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<ApiResponse<Void>> handleValidation(MethodArgumentNotValidException ex) {
        String detail = ex.getBindingResult().getFieldErrors().stream()
                .findFirst()
                .map(fe -> fe.getField() + " " + fe.getDefaultMessage())
                .orElse(ErrorCode.COMMON_0001.getMessage());
        log.info("[Validation] {}", detail);
        return ResponseEntity.status(ErrorCode.COMMON_0001.getHttpStatus())
                .body(ApiResponse.error(ErrorCode.COMMON_0001.getCode(), detail));
    }

    @ExceptionHandler(AccessDeniedException.class)
    public ResponseEntity<ApiResponse<Void>> handleAccessDenied(AccessDeniedException ex) {
        log.info("[AccessDenied] {}", ex.getMessage());
        return ResponseEntity.status(ErrorCode.COMMON_0003.getHttpStatus())
                .body(ApiResponse.error(ErrorCode.COMMON_0003.getCode(), ErrorCode.COMMON_0003.getMessage()));
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ApiResponse<Void>> handleUnknown(Exception ex) {
        log.error("[Unknown] {}", ex.getMessage(), ex);
        return ResponseEntity.status(ErrorCode.COMMON_0002.getHttpStatus())
                .body(ApiResponse.error(ErrorCode.COMMON_0002.getCode(), ErrorCode.COMMON_0002.getMessage()));
    }
}
