import { Link, Outlet, useNavigate } from 'react-router-dom';
import { Button } from '@/shared/components/ui/button';
import { useAuthStore } from '@/store/useAuthStore';
import { MENU_ITEMS } from './menuItems';

const iconMap = {
    upload: Database,
    category: FolderTree,
};

export function MainLayout() {
    const navigate = useNavigate();
    const user = useAuthStore((state) => state.user);
    const logout = useAuthStore((state) => state.logout);

    return (
        <div className='grid min-h-screen bg-slate-100 lg:grid-cols-[220px_1fr]'>
            <aside className='bg-slate-900 px-4 py-6 text-slate-100'>
                <div className='px-3 text-lg font-bold tracking-wide'>TrmWordDict</div>
                <nav className='mt-6 flex flex-col gap-1'>
                    {MENU_ITEMS.filter((item) => !item.requiredRole || item.requiredRole === user?.role).map((item) => {
                        const Icon = iconMap[item.icon] ?? FolderTree;

                        return (
                            <Link
                                key={item.route}
                                className='flex items-center gap-3 rounded-xl px-3 py-3 text-sm text-slate-300 transition hover:bg-slate-800 hover:text-white'
                                to={item.route}
                            >
                                <Icon className='h-4 w-4' />
                                <span>{item.label}</span>
                            </Link>
                        );
                    })}
                </nav>
            </aside>
            <div className='flex min-h-screen flex-col'>
                <header className='flex items-center justify-end border-b border-slate-200 bg-white px-6 py-4'>
                    <span className='mr-3 text-sm font-medium text-slate-600'>{user?.name}</span>
                    <Button
                        variant='ghost'
                        aria-label='濡쒓렇�븘�썐'
                        className='gap-2'
                        onClick={() => {
                            logout();
                            navigate('/login');
                        }}
                    >
                        <LogOut className='h-4 w-4' />
                        <span className='hidden sm:inline'>濡쒓렇�븘�썐</span>
                    </Button>
                </header>
                <main className='flex-1 p-4 md:p-6'>
                    <Outlet />
                </main>
            </div>
        </div>
    );
}
