, "content": "import { useMemo, useState } from 'react';

export const useColumnResize = (columns) => {
    const initialWidths = useMemo(
        () =>
            columns.reduce((acc, column) => {
                if (column.width) {
                    acc[column.key] = column.width;
                }
                return acc;
            }, {}),
        [columns],
    );

    const [widths, setWidths] = useState(initialWidths);

    const getResizeProps = (column) => ({
        onMouseDown: (event) => {
            const startX = event.clientX;
            const startWidth = widths[column.key] ?? column.width ?? event.currentTarget.getBoundingClientRect().width;
            const minWidth = column.minWidth ?? 60;

            const handleMove = (moveEvent) => {
                const nextWidth = Math.max(minWidth, startWidth + moveEvent.clientX - startX);
                setWidths((current) => ({
                    ...current,
                    [column.key]: nextWidth,
                }));
            };

            const handleUp = () => {
                window.removeEventListener('mousemove', handleMove);
                window.removeEventListener('mouseup', handleUp);
            };

            window.addEventListener('mousemove', handleMove);
