import { useCallback, useEffect, useState } from 'react';
import { RouterProvider } from 'react-router-dom';
import { Toaster } from 'sonner';
import { AuthReadyContext } from './ProtectedRoute';
import { router } from './router';
import { getMe } from '@/features/auth/authApi';
import { setUnauthorizedHandler } from '@/core/api/axiosInstance';
import { useAuthStore } from '@/store/useAuthStore';
import { useThemeStore } from '@/store/useThemeStore';

const FIVE_MINUTES_MS = 5 * 60 * 1000;

const ThemeBootstrap = () => {
    const theme = useThemeStore((state) => state.theme);

    useEffect(() => {
        document.documentElement.classList.toggle('dark', theme === 'dark');
    }, [theme]);

    return null;
};

const AuthBootstrap = ({ onReady }) => {
    const setUser = useAuthStore((state) => state.setUser);
    const logout = useAuthStore((state) => state.logout);

    useEffect(() => {
        if (window.location.pathname === '/login') {
            onReady();
            return;
        }

        let cancelled = false;

        getMe()
            .then((user) => {
                if (!cancelled) {
                    setUser(user);
                    onReady();
                }
            })
            .catch(() => {
                if (!cancelled) {
                    logout();
                    onReady();
                }
            });

        return () => {
            cancelled = true;
        };
    }, [logout, onReady, setUser]);

    return null;
};

setUnauthorizedHandler(() => {
    useAuthStore.getState().logout();
});

export const Providers = () => {
    const [authReady, setAuthReady] = useState(false);
    const handleAuthReady = useCallback(() => {
        setAuthReady(true);
    }, []);
    const [queryClient] = useState(
        () =>
            new QueryClient({
                defaultOptions: {
                    queries: {
                        retry: 1,
                        staleTime: FIVE_MINUTES_MS,
                    },
                },
            }),
    );

    return (
        <QueryClientProvider client={queryClient}>
            <ThemeBootstrap />
            <AuthBootstrap onReady={handleAuthReady} />
            <AuthReadyContext value={authReady}>
                <RouterProvider router={router} />
            </AuthReadyContext>
