, "content": "import { cn } from '@/lib/utils';

const EMPTY_CHIPS = [];
const EMPTY_ITEMS = [];

const pillColors = {
    default: 'bg-muted text-muted-foreground',
    accent: 'bg-primary/10 text-primary',
    success: 'bg-emerald-500/10 text-emerald-700 dark:text-emerald-300',
    warning: 'bg-amber-500/10 text-amber-700 dark:text-amber-300',
    danger: 'bg-rose-500/10 text-rose-700 dark:text-rose-300',
};

export const DetailPill = ({ tone = 'default', children, className }) => (
    <span
        className={cn(
            'inline-flex items-center rounded-full px-3 py-1 text-xs font-semibold tracking-wide',
            pillColors[tone] ?? pillColors.default,
            className,
        )}
    >
        {children}
    </span>
);

export const DetailHero = ({ eyebrow, title, description, chips = EMPTY_CHIPS, className }) => (
    <section
        className={cn(
            'rounded-2xl border border-border bg-gradient-to-br from-card via-card to-muted/30 p-5 shadow-sm',
            className,
        )}
    >
        <div className='space-y-4'>
            <div className='space-y-2'>
                {eyebrow ? <p className='text-xs font-semibold uppercase tracking-[0.24em] text-muted-foreground'>{eyebrow}</p> : null}
                <h2 className='text-2xl font-semibold text-card-foreground'>{title}</h2>
                {description ? <p className='max-w-3xl text-sm leading-6 text-muted-foreground'>{description}</p> : null}
            </div>

            {chips.length > 0 ? (
                <div className='flex flex-wrap gap-2'>
                    {chips.map((chip) => (
                        <DetailPill key={`${chip.label}-${chip.value}`} tone={chip.tone ?? 'default'}>
                            {chip.label}
                            {chip.value ? ` 쨌 ${chip.value}` : ''}
                        </DetailPill>
                    ))}
                </div>
            ) : null}
        </div>
    </section>
);

export const DetailStat = ({ label, value, tone = 'default' }) => (
    <div className='rounded-2xl border border-border bg-card p-4 shadow-sm'>
        <div className='text-xs font-semibold uppercase tracking-[0.2em] text-muted-foreground'>{label}</div>
        <div className={cn('mt-2 text-lg font-semibold', tone === 'danger' && 'text-rose-600', tone === 'success' && 'text-emerald-600')}>
            {value ?? '-'}
        </div>
    </div>
);

export const DetailSection = ({ title, description, children, className }) => (
    <section className={cn('rounded-2xl border border-border bg-card p-5 shadow-sm', className)}>
        <div className='mb-4 space-y-1'>
            <h3 className='text-base font-semibold text-card-foreground'>{title}</h3>
            {description ? <p className='text-sm text-muted-foreground'>{description}</p> : null}
        </div>
        {children}
    </section>
);

export const DetailFields = ({ items = EMPTY_ITEMS, columns = 2, className }) => (
    <dl
        className={cn(
            'grid gap-x-4 gap-y-3 text-sm',
            columns === 1 && 'grid-cols-1',
            columns === 2 && 'md:grid-cols-[160px_minmax(0,1fr)]',
            columns === 3 && 'md:grid-cols-[160px_minmax(0,1fr)_160px_minmax(0,1fr)]',
            className,
        )}
    >
        {items.map((item) => (
            <div key={item.label} className={cn('contents', item.fullWidth && 'md:col-span-2')}>
                <dt className='text-muted-foreground'>{item.label}</dt>
                <dd className='min-w-0 break-words text-card-foreground'>{item.value ?? '-'}</dd>
            </div>
        ))}
    </dl>
);
